  5	import * as _ from 'lodash-es';
  6	import {
  7	  Grid,
  8	  GridItem,
  9	  Progress,
 10	  ProgressMeasureLocation,
 11	  ProgressVariant,
 12	  Title,
 13	  Tooltip,
 14	  Button,
 15	  Popover,
 16	} from '@patternfly/react-core';
 17	import { DataUnavailableError } from '../../generic/Error';
 18	import ResourceLink from '../../resource-link/resource-link';
 19	import { HumanizeResult } from '../../types';
 20	import { useCustomTranslation } from '../../useCustomTranslationHook';
 21	import { getDashboardLink } from '../../utils';
 22	import { humanizeBinaryBytes } from '../../utils/humanize';
 23	import './capacity-card.scss';
 24	
 25	export type CapacityMetricDatum = {
 26	  name: string;
 27	  namespace?: string;
 28	  managedSystemName?: string;
 29	  managedSystemKind?: string;
 30	  totalValue?: HumanizeResult;
 31	  usedValue: HumanizeResult;
 32	};
 33	
 34	type CapacityCardProps = {
 35	  data: CapacityMetricDatum[];
 36	  relative?: boolean;
 37	  loading?: boolean;
 38	  resourceModel?: K8sKind;
 39	  showPercentage?: boolean;
 40	  isExternalObjectCapacityCard?: boolean;
 41	};
 42	
 43	const getPercentage = (item: CapacityMetricDatum) =>
 44	  (humanizeBinaryBytes(
 45	    item?.usedValue?.value,
 46	    item?.usedValue?.unit,
 47	    item?.totalValue?.unit
 48	  )?.value /
 49	    item?.totalValue?.value) *
 50	  100;
 51	
 52	const sortMetrics = (
 53	  metrics: CapacityMetricDatum[],
 54	  direction: 'ASC' | 'DESC' = 'ASC',
 55	  relative = false
 56	): CapacityMetricDatum[] => {
 57	  metrics.sort((a, b) => {
 58	    let comparatorA = a.usedValue.value;
 59	    const comparatorB = humanizeBinaryBytes(
 60	      b.usedValue.value,
 61	      b.usedValue.unit,
 62	      a.usedValue.unit
 63	    ).value;
 64	    if (!relative) {
 65	      comparatorA = getPercentage(a);
 66	      comparatorA = getPercentage(b);
 67	    }
 68	    if (comparatorA < comparatorB) {
 69	      return direction === 'ASC' ? -1 : 1;
 70	    }
 71	    if (comparatorB > comparatorA) {
 72	      return direction === 'ASC' ? 1 : -1;
 73	    }
 74	    return 0;
 75	  });
 76	  return metrics;
 77	};
 78	
 79	type CapacityCardHeaderProps = {
 80	  showPercentage: boolean;
 81	  isExternalObjectCapacityCard: boolean;
 82	};
 83	
 84	const CapacityCardHeader: React.FC<CapacityCardHeaderProps> = ({
 85	  showPercentage,
 86	  isExternalObjectCapacityCard,
 87	}) => {
 88	  const { t } = useCustomTranslation();
 89	  return !isExternalObjectCapacityCard ? (
 90	    <>
 91	      <GridItem span={2}>
 92	        <Title headingLevel="h3" size="md">
 93	          {t('Name')}
 94	        </Title>
 95	      </GridItem>
 96	      <GridItem span={7}>
 97	        <Title headingLevel="h3" size="md">
 98	          {t('Used capacity')} {showPercentage && <>%</>}
 99	        </Title>
100	      </GridItem>
101	      <GridItem span={3}>
102	        <Title headingLevel="h3" size="md">
103	          {t('Used / Total')}
104	        </Title>
105	      </GridItem>
106	    </>
107	  ) : (
108	    <Grid>
109	      <GridItem span={5}>
110	        <Title headingLevel="h3" size="md">
111	          {t('Name')}
112	        </Title>
113	      </GridItem>
114	      <GridItem span={5}>
115	        <Title headingLevel="h3" size="md">
116	          {t('Used capacity')}
117	        </Title>
118	      </GridItem>
119	    </Grid>
120	  );
