123	type CapacityCardRowProps = {
124	  data: CapacityMetricDatum;
125	  isRelative?: boolean;
126	  isPercentage?: boolean;
127	  largestValue?: HumanizeResult;
128	  resourceModel?: K8sKind;
129	  isExternalObjectCapacityCard?: boolean;
130	};
