132	const getProgress = (
133	  data: CapacityMetricDatum,
134	  isRelative: boolean,
135	  largestValue: HumanizeResult
136	) => {
137	  if (isRelative) {
138	    return (
139	      (humanizeBinaryBytes(
140	        data?.usedValue?.value,
141	        data?.usedValue?.unit,
142	        largestValue?.unit
143	      )?.value /
144	        largestValue?.value) *
145	      100
146	    );
147	  }
148	  return getPercentage(data);
149	};
