151	const CapacityCardRow: React.FC<CapacityCardRowProps> = ({
152	  data,
153	  isPercentage,
154	  isRelative,
155	  largestValue,
156	  resourceModel,
157	  isExternalObjectCapacityCard,
158	}) => {
159	  const { t } = useCustomTranslation();
160	  const progress =
161	    (!isPercentage && isRelative) || (isPercentage && !isRelative)
162	      ? getProgress(data, isRelative, largestValue)
163	      : data?.usedValue?.value > 0
164	        ? 100
165	        : 0;
166	  const value = isPercentage
167	    ? `${data?.usedValue?.string} / ${data?.totalValue?.string}`
168	    : data?.usedValue?.string;
169	  const variant = (() => {
170	    if (!isPercentage) {
171	      return null;
172	    }
173	    if (progress >= 80) {
174	      return ProgressVariant.danger;
175	    }
176	    if (progress >= 75) {
177	      return ProgressVariant.warning;
178	    }
179	  })();
180	
181	  const dataUnavailable = _.isNaN(progress);
182	  return !isExternalObjectCapacityCard ? (
183	    <>
184	      <GridItem key={`${data?.name}~name`} span={2}>
185	        {data?.managedSystemKind ? (
186	          <Tooltip content={data?.name}>
187	            <ResourceLink
188	              link={getDashboardLink(
189	                data?.managedSystemKind,
190	                data?.name,
191	                data?.namespace
192	              )}
193	              resourceModel={resourceModel}
194	              resourceName={data?.name}
195	              className="odf-capacityCardLink--ellipsis"
196	              hideIcon
197	            />
198	          </Tooltip>
199	        ) : (
200	          <PlainResourceName resourceName={data?.name} />
201	        )}
202	      </GridItem>
203	      <GridItem key={`${data?.name}~progress`} span={7}>
204	        {isRelative || !isPercentage ? (
205	          <Progress
206	            value={dataUnavailable ? 0 : progress}
207	            label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
208	            size="md"
209	            measureLocation={
210	              !isPercentage
211	                ? ProgressMeasureLocation.none
212	                : ProgressMeasureLocation.outside
213	            }
214	            variant={variant}
215	          />
216	        ) : (
217	          <Tooltip
218	            content={!dataUnavailable ? <>{progress.toFixed(2)} %</> : null}
219	          >
220	            <Progress
221	              value={dataUnavailable ? null : progress}
222	              label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
223	              size="md"
224	              measureLocation={ProgressMeasureLocation.outside}
225	              variant={variant}
226	            />
227	          </Tooltip>
228	        )}
229	      </GridItem>
230	      <GridItem span={3} key={`${data?.name}~value`}>
231	        {dataUnavailable ? '-' : value}
232	        {value && !dataUnavailable && !isPercentage && (
233	          <span>
234	            &nbsp; / &nbsp;
235	            <Popover
236	              position="right"
237	              bodyContent={t(
238	                'For standalone MCG clusters, there is no set limit.'
239	              )}
240	            >
241	              <Button variant="plain" className="details-item__popover-button">
242	                {t('No Limit')}
243	              </Button>
244	            </Popover>
245	          </span>
246	        )}
247	      </GridItem>
248	    </>
249	  ) : (
250	    <Grid>
251	      <GridItem key={`${data?.name}~name`} span={5}>
252	        <PlainResourceName resourceName={data?.name} />
253	      </GridItem>
254	      <GridItem span={5} key={`${data?.name}~value`}>
255	        {dataUnavailable ? '-' : value}
256	      </GridItem>
257	    </Grid>
258	  );
259	};
