296	const CapacityCard: React.FC<CapacityCardProps> = ({
297	  data,
298	  relative = false,
299	  loading,
300	  resourceModel,
301	  showPercentage,
302	  isExternalObjectCapacityCard,
303	}) => {
304	  const safeData = data.every(
305	    (item) => item.totalValue !== undefined && item.usedValue !== undefined
306	  );
307	  const sortedMetrics = safeData ? sortMetrics(data, 'ASC', relative) : data;
308	  const error = _.isEmpty(sortedMetrics);
309	  return (
310	    <div
311	      className={classNames('o-capacityCard', {
312	        'o-capacityCard--centered': error,
313	      })}
314	    >
315	      {!error && !loading && (
316	        <Grid hasGutter>
317	          <CapacityCardHeader
318	            showPercentage={showPercentage}
319	            isExternalObjectCapacityCard={isExternalObjectCapacityCard}
320	          />
321	          {sortedMetrics?.map((item) => {
322	            const isPercentage = !!item?.totalValue;
323	            return (
324	              <CapacityCardRow
325	                key={`${item.name}${item.namespace}`}
326	                data={item}
327	                isPercentage={isPercentage}
328	                isRelative={relative}
329	                largestValue={sortedMetrics?.[0]?.usedValue}
330	                resourceModel={resourceModel}
331	                isExternalObjectCapacityCard={isExternalObjectCapacityCard}
332	              />
333	            );
334	          })}
335	        </Grid>
336	      )}
337	      {error && !loading && <DataUnavailableError />}
338	      {loading && <CapacityCardLoading />}
339	    </div>
340	  );
341	};
342	
343	export default CapacityCard;

